  tags = {
    Name = "main-vpc"
  }
}

resource "aws_route53_zone" "private_zone" {
  name = "internal.example53.com" 

  vpc {
    vpc_id = aws_vpc.main.id  
    }
}


resource "aws_route53_record" "internal_record" {
  zone_id = aws_route53_zone.private_zone.zone_id
  name    = "api.internal.example53.com"
  type    = "A"
  ttl     = "300"
  records = ["10.0.1.101"]  
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

# Health check for the primary resource
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "example.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Primary A record with a health check (active endpoint)
resource "aws_route53_record" "primary_record" {
  zone_id           = aws_route53_zone.primary.zone_id
  name              = "example.com"
  type              = "A"
  ttl               = "60"
  records           = ["192.0.2.10"]
  set_identifier    = "primary"
  health_check_id   = aws_route53_health_check.primary_health_check.id

  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Secondary A record without a health check (passive endpoint)
resource "aws_route53_record" "secondary_record" {
  zone_id           = aws_route53_zone.primary.zone_id
  name              = "example.com"
  type              = "A"
  ttl               = "60"
  records           = ["192.0.2.20"]
  set_identifier    = "secondary"

  failover_routing_policy {
    type = "SECONDARY"
  }
}

